// Make the arcs diameter as large as possible within canvas height, but limit by width val maxDiameterByHeight = canvasHeight * 2.2f val maxDiameterByWidth = (canvasWidth * 0.9f) val diameter = min(maxDiameterByHeight, maxDiameterByWidth)
// Calculate bounding rect for arcs val arcLeft = (canvasWidth - diameter) / 2f val arcTop = with(density) { 100.dp.toPx() } - diameter // Position arcs relative to canvas val arcRect = Rect(arcLeft, arcTop, arcLeft + diameter, arcTop + diameter)
Canvas(modifier = Modifier.fillMaxWidth().height(100.dp)) { // Draw background arcs var angle = startAngle repeat(segments) { drawArc( color = Color.LightGray, startAngle = angle, sweepAngle = segmentSweep, useCenter = false, style = Stroke(width = strokeWidth, cap = StrokeCap.Round), topLeft = arcRect.topLeft, size = arcRect.size ) angle += segmentSweep + gapAngle }
// Draw progress arcs val totalProgressSweep = totalSweep * progress var remainingSweep = totalProgressSweep angle = startAngle
repeat(segments) { val sweep = min(segmentSweep, remainingSweep) if (sweep > 0f) { drawArc( color = Color.Black, startAngle = angle, sweepAngle = sweep, useCenter = false, style = Stroke(width = strokeWidth, cap = StrokeCap.Round), topLeft = arcRect.topLeft, size = arcRect.size ) } remainingSweep -= segmentSweep angle += segmentSweep + gapAngle } }
// Text centered below the arcs Column( horizontalAlignment = Alignment.CenterHorizontally, modifier = Modifier .fillMaxWidth() .offset(y = 80.dp) // Changed from (-124).dp to 80.dp to position below arcs ) { Text( text = "${maxCalories - currentCalories}", fontSize = 32.sp, color = Color.Black, fontWeight = FontWeight.Bold ) Text( text = "Total calories left", fontSize = 14.sp, color = Color.Gray ) } } }

@Composable
fun ShimmerMealName(
    modifier: Modifier = Modifier
) {
    Box(
        modifier = modifier
            .fillMaxWidth()
            .height(28.dp)
            .clip(RoundedCornerShape(4.dp))
            .background(shimmerBrush())
    )
}

@Composable
fun ShimmerText(
    width: Dp,
    height: Dp = 16.dp,
    modifier: Modifier = Modifier
) {
    Box(
        modifier = modifier
            .width(width)
            .height(height)
            .clip(RoundedCornerShape(4.dp))
            .background(shimmerBrush())
    )
}

@Composable
fun ShimmerHealthScore(
    modifier: Modifier = Modifier
) {
    Column(
        modifier = modifier.fillMaxWidth(),
        horizontalAlignment = Alignment.CenterHorizontally
    ) {
        // Title shimmer
        ShimmerText(width = 100.dp, height = 18.dp)

        Spacer(modifier = Modifier.height(8.dp))

        // Grade shimmer
        Box(
            modifier = Modifier
                .size(60.dp)
                .clip(RoundedCornerShape(8.dp))
                .background(shimmerBrush())
        )

        Spacer(modifier = Modifier.height(8.dp))

        // Description shimmer
        ShimmerText(width = 120.dp, height = 14.dp)
    }
}

@Composable
fun ShimmerShareAndQuantity(
    modifier: Modifier = Modifier
) {
    Row(
        modifier = modifier.fillMaxWidth(),
        horizontalArrangement = Arrangement.SpaceBetween,
        verticalAlignment = Alignment.CenterVertically
    ) {
        // Share button shimmer
        Box(
            modifier = Modifier
                .width(80.dp)
                .height(40.dp)
                .clip(RoundedCornerShape(20.dp))
                .background(shimmerBrush())
        )

        // Quantity controls shimmer
        Row(
            verticalAlignment = Alignment.CenterVertically,
            horizontalArrangement = Arrangement.spacedBy(16.dp)
        ) {
            Box(
                modifier = Modifier
                    .size(32.dp)
                    .clip(RoundedCornerShape(16.dp))
                    .background(shimmerBrush())
            )
            ShimmerText(width = 30.dp, height = 20.dp)
            Box(
                modifier = Modifier
                    .size(32.dp)
                    .clip(RoundedCornerShape(16.dp))
                    .background(shimmerBrush())
            )
        }
    }
}

@Composable
fun ShimmerIngredientCard(
    modifier: Modifier = Modifier
) {
    Card(
        modifier = modifier.fillMaxWidth(),
        colors = CardDefaults.cardColors(containerColor = Color.White),
        elevation = CardDefaults.cardElevation(defaultElevation = 2.dp)
    ) {
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .padding(16.dp),
            verticalAlignment = Alignment.CenterVertically,
            horizontalArrangement = Arrangement.SpaceBetween
        ) {
            Column(
                modifier = Modifier.weight(1f)
            ) {
                ShimmerText(width = 120.dp, height = 16.dp)
                Spacer(modifier = Modifier.height(4.dp))
                ShimmerText(width = 80.dp, height = 14.dp)
            }

            ShimmerText(width = 60.dp, height = 16.dp)
        }
    }
}

